+    #[test]
+    fn version_gte_non_numeric_filtered_out() {
+        // "14.beta.2" → [14, 2] vs "14.1" → [14, 1]
+        // Comparing [14,2] vs [14,1] → 14==14, 2>1 → true
+        assert!(version_gte("14.beta.2", "14.1"));
